{#-
  Sales Invoice Pick List — Mizan/PALCO style.
  Brand is resolved from cost center (e.g. "Ahuhu - KPG" -> Brand "Ahuhu").
  Brand lookup is inline (using frappe.db.get_value) so the template works
  even if the order_picking.jinja helpers aren't registered in jenv.
-#}
{# 1) Explicit mapping via Cost Center.custom_brand (preferred). #}
{# 2) Else strip " - <Company>" suffix and match Brand by exact name. #}
{# 3) Else try the first word of the cleaned name (e.g. "Ahuhu Care" -> "Ahuhu"). #}
{%- set _cc_brand = frappe.db.get_value('Cost Center', doc.cost_center, 'custom_brand') if doc.cost_center else None -%}
{%- set _cc = (doc.cost_center or '').rsplit(' - ', 1)[0].strip() -%}
{%- set _tried = [] -%}
{%- set _brow = None -%}
{%- if _cc_brand -%}
  {%- set _ = _tried.append('Cost Center.custom_brand=' ~ _cc_brand) -%}
  {%- set _brow = frappe.db.get_value('Brand', _cc_brand, ['name', 'image'], as_dict=True) -%}
{%- endif -%}
{%- if (not _brow) and _cc -%}
  {%- set _ = _tried.append(_cc) -%}
  {%- set _brow = frappe.db.get_value('Brand', _cc, ['name', 'image'], as_dict=True) -%}
{%- endif -%}
{%- if (not _brow) and _cc and ' ' in _cc -%}
  {%- set _first = _cc.split(' ', 1)[0] -%}
  {%- set _ = _tried.append(_first) -%}
  {%- set _brow = frappe.db.get_value('Brand', _first, ['name', 'image'], as_dict=True) -%}
{%- endif -%}
{%- set _bimg = (_brow.image if _brow else None) -%}
{%- if _bimg and not (_bimg.startswith('http://') or _bimg.startswith('https://') or _bimg.startswith('data:')) -%}
  {%- set _bimg = frappe.utils.get_url(_bimg) -%}
{%- endif -%}
{%- set brand = {'name': (_brow.name if _brow else (_cc or doc.company)), 'image': _bimg, 'found': (_brow is not none), 'tried': _tried} -%}

{# ── Product Bundle expansion ────────────────────────────────────
   doc.packed_items is populated by ERPNext whenever a Sales Invoice line
   is a Product Bundle. It contains the actual physical items to pick,
   linked back to their bundle parent via `parent_item` (item_code) and
   `parent_detail_docname` (the bundle row's child-row name).
   For the pick list we hide the bundle parent rows and show only the
   sub-items, grouped under a header so the picker knows which bundle. #}
{%- set _packed = doc.packed_items or [] -%}
{%- set _bundle_parents = _packed | map(attribute='parent_item') | unique | list -%}
{%- set _regular_items = doc.items | rejectattr('item_code', 'in', _bundle_parents) | list -%}
{%- set _bundle_items  = doc.items | selectattr('item_code', 'in', _bundle_parents) | list -%}

{%- set total_lines = (_regular_items | length) + (_packed | length) -%}
{%- set total_qty = (_regular_items | sum(attribute='qty')) + (_packed | sum(attribute='qty')) -%}
{%- macro barcode(v, h='40', w='1.0') -%}
  <span class="bc-wrap">
    <svg class="js-barcode" data-value="{{ v }}" data-bar-w="{{ w }}" data-bar-h="{{ h }}"></svg>
    <span class="bc-text">{{ v }}</span>
  </span>
{%- endmacro -%}

<style>
  @page { margin: 12mm 14mm 16mm; }

  /* ── base ────────────────────────────────────────────────────────── */
  body {
    font-family: "Inter", system-ui, -apple-system, "Segoe UI", Arial, sans-serif;
    color: #1f2937; font-size: 12px; line-height: 1.5;
    -webkit-font-smoothing: antialiased;
  }
  .num { font-variant-numeric: tabular-nums; }

  /* ── top status strip ────────────────────────────────────────────── */
  .top-strip {
    display: flex; justify-content: space-between; align-items: center;
    margin-bottom: 18px;
  }
  .pill {
    display: inline-block;
    padding: 6px 14px;
    border: 1.5px solid #16a34a;
    color: #16a34a;
    border-radius: 4px;
    font-size: 10px; font-weight: 700;
    letter-spacing: 1.2px; text-transform: uppercase;
  }
  .printed-ts { font-size: 10px; color: #6b7280; }

  /* ── header ──────────────────────────────────────────────────────── */
  .head {
    display: flex; justify-content: space-between; align-items: flex-start;
    margin-bottom: 12px;
  }
  .head .left .doc-kind {
    font-size: 12px; font-weight: 700; color: #1f2937;
    letter-spacing: 0.6px; margin-bottom: 4px;
  }
  .head .left .brand-name {
    font-size: 32px; font-weight: 800; color: #0f172a;
    letter-spacing: -0.4px; line-height: 1;
  }
  .head .left .brand img {
    max-height: 56px; max-width: 240px; object-fit: contain;
    display: block; margin-top: 2px;
  }
  .head .right { text-align: right; font-size: 12px; line-height: 1.7; }
  .head .right .kv { color: #6b7280; }
  .head .right .kv strong { color: #1f2937; font-weight: 700; }
  .head .right .inv-barcode {
    display: inline-block; margin-top: 6px;
    padding: 6px 10px 4px;
    border: 1px solid #e5e7eb; border-radius: 4px;
    background: #fff; line-height: 0;
  }
  .head .right .inv-barcode .bc-wrap { display: block; }
  .head .right .inv-barcode .bc-wrap svg {
    display: block; height: 44px; max-width: 240px;
  }
  .head .right .inv-barcode .bc-text {
    display: block; margin-top: 3px;
    font-family: "Courier New", ui-monospace, monospace;
    font-size: 10px; color: #4b5563; letter-spacing: 0.6px;
    line-height: 1.2; text-align: center;
  }
  .head .right .inv-barcode .bc-fallback {
    display: inline-block;
    font-family: "Courier New", ui-monospace, monospace;
    font-size: 11px; color: #0f172a;
    background: #f3f4f6; padding: 4px 8px; border-radius: 3px;
    letter-spacing: 1.5px;
  }
  .rule { border: 0; border-top: 1px solid #e5e7eb; margin: 4px 0 18px; }

  /* ── info card ───────────────────────────────────────────────────── */
  .info-card {
    border: 1px solid #e5e7eb; border-radius: 6px;
    padding: 14px 18px; margin-bottom: 20px;
  }
  .info-card .row {
    display: grid; grid-template-columns: 1fr 1fr;
    gap: 8px 24px;
  }
  .info-card .item .k { color: #6b7280; }
  .info-card .item .v { color: #1f2937; font-weight: 700; margin-left: 4px; }

  /* ── section title ───────────────────────────────────────────────── */
  .sec-title {
    display: flex; align-items: center; margin: 0 0 10px;
    font-size: 12px; font-weight: 700; letter-spacing: 0.8px;
    text-transform: uppercase; color: #1f2937;
  }
  .sec-title::before {
    content: ""; display: inline-block;
    width: 3px; height: 14px; background: #16a34a;
    margin-right: 10px; border-radius: 1px;
  }
  .sec-sub { font-size: 11px; color: #6b7280; margin: -6px 0 12px; }

  /* ── metric strip (Total Lines / Qty / Printed) ──────────────────── */
  .metrics {
    display: grid; grid-template-columns: repeat(3, 1fr);
    gap: 12px; margin-bottom: 20px;
  }
  .metric {
    border: 1px solid #e5e7eb; border-radius: 6px;
    padding: 12px 16px;
  }
  .metric .k {
    font-size: 10px; font-weight: 700; letter-spacing: 1px;
    text-transform: uppercase; color: #6b7280; margin-bottom: 4px;
  }
  .metric .v {
    font-size: 22px; font-weight: 800; color: #0f172a;
    line-height: 1.1; letter-spacing: -0.3px;
  }
  .metric .sub { font-size: 10px; color: #9ca3af; margin-top: 2px; }

  /* ── items table ─────────────────────────────────────────────────── */
  table.items {
    border-collapse: collapse; width: 100%;
    border: 1px solid #e5e7eb; border-radius: 6px;
  }
  table.items thead th {
    background: #f9fafb; color: #374151;
    text-align: left; padding: 10px 12px;
    font-size: 10.5px; font-weight: 700;
    letter-spacing: 0.5px; text-transform: uppercase;
    border-bottom: 1px solid #e5e7eb;
  }
  table.items thead th.r { text-align: right; }
  table.items thead th.c { text-align: center; }
  table.items tbody tr { page-break-inside: avoid; }
  table.items tbody td {
    padding: 12px; border-bottom: 1px solid #f1f5f9;
    font-size: 12px; vertical-align: middle;
  }
  table.items tbody tr:last-child td { border-bottom: 0; }
  table.items tbody td.r { text-align: right; }
  table.items tbody td.c { text-align: center; }

  /* ── bundle parent (header row) + sub-items ──────────────────────── */
  table.items tbody tr.bundle-header td {
    background: #ecfdf5 !important;
    border-top: 2px solid #16a34a;
    padding: 8px 12px;
    font-size: 11px; color: #064e3b;
    letter-spacing: 0.2px;
  }
  table.items tbody tr.bundle-header .bundle-badge {
    display: inline-block;
    padding: 2px 8px; margin-right: 8px;
    font-size: 9px; font-weight: 800; letter-spacing: 1.2px;
    text-transform: uppercase;
    background: #16a34a; color: #fff; border-radius: 3px;
  }
  table.items tbody tr.bundle-header .bundle-times {
    color: #16a34a; font-weight: 700;
  }
  table.items tbody tr.bundle-sub td { background: #f0fdf4 !important; }
  table.items tbody tr.bundle-sub .sub-arrow {
    color: #16a34a; font-weight: 700; margin-right: 4px;
  }

  .idx { color: #9ca3af; width: 28px; }
  .check-box {
    display: inline-block; width: 20px; height: 20px;
    border: 1.5px solid #d1d5db; border-radius: 3px;
    vertical-align: middle;
  }
  .sku {
    font-size: 13px; font-weight: 700; color: #0f172a; letter-spacing: 0.2px;
  }
  .iname {
    font-size: 11px; color: #4b5563; margin-top: 3px; line-height: 1.4;
  }
  .qty-big {
    font-size: 20px; font-weight: 800; color: #0f172a; letter-spacing: -0.3px;
  }
  .uom-small {
    font-size: 10px; color: #6b7280; margin-left: 4px; font-weight: 500;
  }

  /* ── barcode (client-side rendered via JsBarcode) ────────────────── */
  .bc-wrap { display: inline-block; line-height: 0; }
  .bc-wrap svg { display: block; height: 32px; max-width: 170px; }
  .bc-text {
    display: block; margin-top: 2px;
    font-family: "Courier New", ui-monospace, monospace;
    font-size: 10px; color: #4b5563;
    letter-spacing: 0.5px; line-height: 1.2;
  }
  .bc-fallback {
    display: inline-block;
    font-family: "Courier New", ui-monospace, monospace;
    font-size: 12px; color: #0f172a;
    background: #f3f4f6;
    padding: 6px 10px; border-radius: 3px; letter-spacing: 1.5px;
  }

  /* ── signatures ──────────────────────────────────────────────────── */
  .sigs {
    margin-top: 26px;
    display: grid; grid-template-columns: 1fr 1fr;
    gap: 28px; page-break-inside: avoid;
  }
  .sig {
    border: 1px solid #e5e7eb; border-radius: 6px;
    padding: 14px 16px;
  }
  .sig .k {
    font-size: 10px; font-weight: 700; letter-spacing: 1px;
    text-transform: uppercase; color: #6b7280; margin-bottom: 24px;
  }
  .sig .line { border-bottom: 1px solid #d1d5db; height: 1px; }
  .sig .hint { font-size: 10px; color: #9ca3af; margin-top: 4px; }

  /* ── footer ──────────────────────────────────────────────────────── */
  .footer {
    margin-top: 22px; padding-top: 12px;
    border-top: 1px solid #e5e7eb;
  }
  .footer .company {
    text-align: center;
    font-size: 11px; font-weight: 700; color: #1f2937;
    letter-spacing: 0.4px; margin-bottom: 6px;
  }
  .footer .meta {
    display: flex; justify-content: space-between;
    font-size: 10px; color: #6b7280;
  }
</style>

{# ── Top status strip ────────────────────────────────────────────── #}
<div class="top-strip">
  <span class="pill">Pick List · Warehouse Copy</span>
  <span class="printed-ts">Printed: {{ frappe.utils.format_datetime(frappe.utils.now()) }}</span>
</div>

{# ── Header ──────────────────────────────────────────────────────── #}
<div class="head">
  <div class="left">
    <div class="doc-kind">PICK LIST</div>
    <div class="brand">
      {% if brand.image %}
        <img src="{{ brand.image }}" alt="{{ brand.name }}">
      {% else %}
        <div class="brand-name">{{ (brand.name or doc.company) | upper }}</div>
      {% endif %}
    </div>
  </div>
  <div class="right">
    <div class="kv"><strong>Invoice:</strong> {{ doc.name }}</div>
    <div class="inv-barcode">{{ barcode(doc.name) }}</div>
    <div class="kv"><strong>Lines:</strong> {{ total_lines }}</div>
    <div class="kv">Date: {{ frappe.utils.formatdate(doc.posting_date) }}</div>
  </div>
</div>
<hr class="rule">

{# ── Info card ──────────────────────────────────────────────────── #}
<div class="info-card">
  <div class="row">
    <div class="item">
      <span class="k">Customer:</span><span class="v">{{ doc.customer_name or doc.customer }}</span>
    </div>
    <div class="item">
      <span class="k">Territory:</span><span class="v">{{ doc.territory or '—' }}</span>
    </div>
    <div class="item">
      <span class="k">Invoice Date:</span><span class="v num">{{ frappe.utils.formatdate(doc.posting_date) }}</span>
    </div>
    <div class="item">
      <span class="k">PO No:</span><span class="v">{{ doc.po_no or '—' }}</span>
    </div>
  </div>
</div>

{# ── Pick Summary ───────────────────────────────────────────────── #}
<div class="sec-title">Pick Summary</div>
<div class="metrics">
  <div class="metric">
    <div class="k">Total Lines</div>
    <div class="v num">{{ total_lines }}</div>
    <div class="sub">SKUs to pick (incl. bundle items)</div>
  </div>
  <div class="metric">
    <div class="k">Total Qty</div>
    <div class="v num">{{ total_qty }}</div>
    <div class="sub">Units across all lines</div>
  </div>
  <div class="metric">
    <div class="k">Generated</div>
    <div class="v num" style="font-size:14px">{{ frappe.utils.format_datetime(frappe.utils.now()) }}</div>
    <div class="sub">Print timestamp</div>
  </div>
</div>

{# ── Items ──────────────────────────────────────────────────────── #}
{%- macro pick_row(idx, item_code, item_name, qty, uom, warehouse, is_sub=False) -%}
  {%- set bcs = frappe.db.get_all('Item Barcode',
        filters={'parent': item_code}, fields=['barcode'],
        order_by='idx asc', limit=1) -%}
  {%- set bc = bcs[0].barcode if bcs else item_code -%}
  <tr{% if is_sub %} class="bundle-sub"{% endif %}>
    <td class="idx num">{{ idx }}</td>
    <td class="c"><span class="check-box"></span></td>
    <td>
      <div class="sku">{% if is_sub %}<span class="sub-arrow">↳</span> {% endif %}{{ item_code }}</div>
      {% if item_name and item_name != item_code %}
        <div class="iname">{{ item_name }}</div>
      {% endif %}
    </td>
    <td>{{ barcode(bc, h='32', w='0.9') }}</td>
    <td class="r">
      <span class="qty-big num">{{ qty }}</span>
      <span class="uom-small">{{ uom or 'Nos' }}</span>
    </td>
    <td style="font-size:11px; color:#4b5563">{{ warehouse or '—' }}</td>
  </tr>
{%- endmacro -%}

<div class="sec-title">Items</div>
<table class="items">
  <thead>
    <tr>
      <th class="idx">#</th>
      <th class="c" style="width:32px">✓</th>
      <th>Item</th>
      <th>Barcode</th>
      <th class="r">Qty</th>
      <th>Warehouse</th>
    </tr>
  </thead>
  <tbody>
    {%- set ns = namespace(idx=0) -%}

    {# Regular (non-bundle) items #}
    {% for item in _regular_items %}
      {%- set ns.idx = ns.idx + 1 -%}
      {{ pick_row(ns.idx, item.item_code, item.item_name, item.qty, item.uom, item.warehouse) }}
    {% endfor %}

    {# Bundle items: header row + each sub-item from packed_items #}
    {% for item in _bundle_items %}
    <tr class="bundle-header">
      <td colspan="6">
        <span class="bundle-badge">BUNDLE</span>
        <strong>{{ item.item_code }}</strong>
        {% if item.item_name and item.item_name != item.item_code %}
          &nbsp;·&nbsp;{{ item.item_name }}
        {% endif %}
        &nbsp;<span class="bundle-times">× {{ item.qty }}</span>
      </td>
    </tr>
    {%- set _subs = _packed | selectattr('parent_detail_docname', 'equalto', item.name) | list -%}
    {%- if not _subs -%}
      {# Fallback when child-row link isn't set: match by parent_item code #}
      {%- set _subs = _packed | selectattr('parent_item', 'equalto', item.item_code) | list -%}
    {%- endif -%}
    {% for sub in _subs %}
      {%- set ns.idx = ns.idx + 1 -%}
      {{ pick_row(ns.idx, sub.item_code, sub.item_name, sub.qty, sub.uom, sub.warehouse, is_sub=True) }}
    {% endfor %}
    {% endfor %}
  </tbody>
</table>

{# ── Signatures ─────────────────────────────────────────────────── #}
<div class="sec-title" style="margin-top:24px">Sign-off</div>
<div class="sigs">
  <div class="sig">
    <div class="k">Picked By</div>
    <div class="line"></div>
    <div class="hint">Signature &amp; date</div>
  </div>
  <div class="sig">
    <div class="k">Checked By</div>
    <div class="line"></div>
    <div class="hint">Signature &amp; date</div>
  </div>
</div>

{# ── Footer ────────────────────────────────────────────────────── #}
<div class="footer">
  <div class="company">{{ doc.company }}</div>
  <div class="meta">
    <div>Printed by: {{ frappe.session.user if frappe.session else '—' }}</div>
    <div>Generated: {{ frappe.utils.format_datetime(frappe.utils.now()) }}</div>
  </div>
</div>
{%- if not brand.found %}
<!-- brand lookup: no Brand record matched. cost_center="{{ doc.cost_center }}", tried={{ brand.tried }} -->
{%- endif %}

{# ── Barcode rendering (client-side, no server deps) ──────────── #}
<script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.6/dist/JsBarcode.all.min.js"></script>
<script>
(function () {
  function render() {
    if (typeof JsBarcode === 'undefined') return setTimeout(render, 50);
    document.querySelectorAll('svg.js-barcode').forEach(function (el) {
      if (el.dataset.rendered) return;
      try {
        JsBarcode(el, el.getAttribute('data-value'), {
          format: 'CODE128',
          width: parseFloat(el.getAttribute('data-bar-w')) || 1.0,
          height: parseFloat(el.getAttribute('data-bar-h')) || 40,
          displayValue: false,
          margin: 2,
        });
        el.dataset.rendered = '1';
      } catch (e) { /* leave svg empty if encoding fails */ }
    });
  }
  render();
})();
</script>
